create schema if not exists app;create or replace function app.current_user_id() returns uuidlanguage sql stable as $$ select auth.uid() $$;create or replace function app.current_tenant_id() returns uuidlanguage sql stable as $$  select tm.tenant_id from public.tenant_memberships tm  where tm.user_id = auth.uid() and tm.status = 'active'  limit 1$$;create or replace function app.has_role(roles text[]) returns booleanlanguage sql stable as $$  select exists (    select 1 from public.tenant_memberships tm    where tm.user_id = auth.uid()      and tm.tenant_id = app.current_tenant_id()      and tm.role = any(roles)      and tm.status = 'active'  )$$;